          manifest,
          summary,
          backlinkManifests,
          t,
          reportBaseUrl,
          transcriptEvents,
        )
        const outPath = transcriptOutputPath(output, manifest)
        mkdirSync(dirname(outPath), { recursive: true })
        writeFileSync(outPath, html, 'utf-8')
        } catch (err: unknown) {
