  const todoFiles = loadMarkdownFiles(join(root, 'Memory', '02_todos'))
  const knowledgeFiles = loadMarkdownFiles(join(root, 'Memory', '04_knowledge'))
  const archiveFiles = loadMarkdownFiles(join(root, 'Memory', '05_archive'))

