export const TOOL_RESULT_TYPES: ReadonlySet<string> = new Set(['tool_result'])

const ALL_SKIP_TYPES: ReadonlySet<string> = new Set([
  ...SKIP_BLOCK_TYPES, ...TOOL_USE_TYPES, ...TOOL_RESULT_TYPES,
