  const currentDt = parseIsoTimestamp(current)
  const normalizedDt = parseIsoTimestamp(normalized)
  if (currentDt !== null && normalizedDt !== null) {
    return normalizedDt < currentDt ? normalized : current
  }
  if (normalizedDt !== null) {
    return normalized
  }
